import "./index.css";
import { initialCards } from "../utils/constants.js";

// ================= DOM =================
const editBtn = document.querySelector(".profile__edit-btn");
const addBtn = document.querySelector(".profile__add-btn");

const editModal = document.querySelector("#edit-profile-modal");
const addModal = document.querySelector("#new-post-modal");

const profileName = document.querySelector(".profile__name");
const profileDesc = document.querySelector(".profile__description");

const nameInput = document.querySelector("#profile-name-input");
const descInput = document.querySelector("#profile-description-input");

const cardTitleInput = document.querySelector("#card-title-input");
const cardLinkInput = document.querySelector("#card-link-input");

const profileForm = document.querySelector("#profile-form");
const addForm = document.querySelector("#add-card-form");

const cardsContainer = document.querySelector(".cards__list");
const template = document.querySelector("#card-template").content;

// ================= MODALS =================
function openModal(modal) {
  modal.classList.add("modal_is-opened");
}

function closeModal(modal) {
  modal.classList.remove("modal_is-opened");
}

// close buttons
document.querySelectorAll(".modal__close-btn").forEach((btn) => {
  btn.addEventListener("click", () => {
    closeModal(btn.closest(".modal"));
  });
});

// ================= OPEN MODALS =================
editBtn.addEventListener("click", () => {
  // fill inputs (this hides placeholder intentionally)
  nameInput.value = profileName.textContent;
  descInput.value = profileDesc.textContent;

  openModal(editModal);
});

addBtn.addEventListener("click", () => {
  addForm.reset(); // shows placeholders again
  openModal(addModal);
});

// ================= PROFILE SUBMIT =================
profileForm.addEventListener("submit", (e) => {
  e.preventDefault();

  profileName.textContent = nameInput.value;
  profileDesc.textContent = descInput.value;

  closeModal(editModal);
});

// ================= ADD CARD =================
addForm.addEventListener("submit", (e) => {
  e.preventDefault();

  const newCard = {
    name: cardTitleInput.value,
    link: cardLinkInput.value,
  };

  renderCard(newCard);
  addForm.reset();
  closeModal(addModal);
});

// ================= CARD =================
function createCard(data) {
  const card = template.cloneNode(true);

  const img = card.querySelector(".card__image");
  const title = card.querySelector(".card__title");
  const likeBtn = card.querySelector(".card__like-btn");
  const deleteBtn = card.querySelector(".card__delete-btn");

  img.src = data.link;
  img.alt = data.name;
  title.textContent = data.name;

  likeBtn.addEventListener("click", () => {
    likeBtn.classList.toggle("card__like-btn_active");
  });

  deleteBtn.addEventListener("click", () => {
    deleteBtn.closest(".card").remove();
  });

  return card;
}

function renderCard(data) {
  cardsContainer.prepend(createCard(data));
}

// ================= INITIAL CARDS =================
initialCards.forEach(renderCard);
